    [CascadingParameter]
    public Task<AuthenticationState> AuthState { get; set; }

    private bool isAuthenticated = false;
    private string userName = "me";
    private bool isAdminUser = false;
    private bool isCashier = false;
    private bool isManager = false;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthState;

        if (authState.User.Identity.IsAuthenticated)
        {
            isAuthenticated = true;


            //  userName = authState.User.FindFirst(System.Security.Claims.ClaimTypes.Name).Value;
            userName = authState.User.FindFirst(System.IdentityModel.Tokens.Jwt.JwtRegisteredClaimNames.Name).Value;
            isAdminUser = authState.User.IsInRole("Admin");
            isCashier = authState.User.IsInRole("Cashier");
            isManager = authState.User.IsInRole("Manager");



        }
    }

